import { createClient } from '@/lib/supabase/server';
import AddBookForm from '@/components/admin/AddBookForm';
import DeleteBookButton from '@/components/admin/DeleteBookButton';
import { Book as BookType } from '@/types';
import { Pencil, Filter, BookOpen, Search, Languages, User, Tag, ArrowRight, Sparkles } from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { getAdminPermissions } from '@/lib/supabase/permissions';

export const metadata = {
  title: 'Books Library | Admin Portal',
};

interface PageProps {
  searchParams: Promise<{ q?: string }>;
}

export default async function AdminBooksPage({ searchParams }: PageProps) {
  const { q } = await searchParams;
  const supabase = await createClient();
  
  const { data: { user } } = await supabase.auth.getUser();
  const permissions = user ? await getAdminPermissions(user.id) : null;

  let query = supabase
    .from('books')
    .select('*')
    .order('created_at', { ascending: false });

  if (q) {
    query = query.or(`title.ilike.%${q}%,author.ilike.%${q}%,genre.ilike.%${q}%`);
  }

  const { data: books, error } = await query;

  if (error) {
    console.error('Error fetching books for admin:', error);
  }

  return (
    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-8">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <div className="w-2 h-8 bg-saffron rounded-full shadow-[0_0_15px_rgba(245,158,11,0.5)]" />
            <h1 className="text-5xl font-bold font-heading text-white tracking-tight">
              Books <span className="text-white/40">Library</span>
            </h1>
          </div>
          <p className="text-white/50 font-medium italic pl-5">Manage and curate the collection of spiritual wisdom.</p>
        </div>
        <div className="flex items-center gap-4">
          <Button variant="outline" size="sm" leftIcon={<Filter size={16} />} className="border-white/10 text-white/70 hover:text-white hover:bg-white/10 backdrop-blur-xl rounded-2xl transition-all duration-500 h-12 px-6">
            Refine View
          </Button>
          {permissions?.can_write && <AddBookForm />}
        </div>
      </div>

      {/* Search Bar */}
      <div className="relative group">
        <div className="absolute inset-0 bg-saffron/10 blur-3xl rounded-[2.5rem] opacity-0 group-focus-within:opacity-100 transition-opacity duration-700" />
        <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-white/20 group-focus-within:text-saffron transition-all duration-500" size={22} />
        <form action="/admin/books" method="GET" className="relative">
           <input 
            name="q"
            defaultValue={q}
            placeholder="Search the archive of wisdom..." 
            className="w-full bg-white/[0.03] border border-white/10 rounded-[2rem] py-6 pl-16 pr-8 text-white placeholder:text-white/10 focus:outline-none focus:border-saffron/40 focus:bg-white/[0.06] transition-all duration-500 backdrop-blur-3xl shadow-2xl text-lg font-medium italic"
          />
        </form>
      </div>

      <div className="glass-card overflow-hidden border border-white/5 shadow-2xl rounded-[2.5rem] bg-white/[0.02] backdrop-blur-3xl">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-white/[0.03] border-b border-white/10 text-white/30 text-[10px] font-black uppercase tracking-[0.3em]">
                <th className="px-10 py-7">Manuscript Details</th>
                <th className="px-10 py-7 text-center">Language</th>
                <th className="px-10 py-7">Category</th>
                <th className="px-10 py-7">Visibility</th>
                <th className="px-10 py-7 text-right">Management</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {books && books.length > 0 ? (
                books.map((book: BookType) => (
                  <tr key={book.id} className="hover:bg-white/[0.04] transition-all duration-500 group">
                    <td className="px-10 py-8">
                      <div className="flex flex-col gap-2">
                        <div className="font-bold text-white group-hover:text-saffron transition-colors text-xl tracking-tight italic">
                          {book.title}
                        </div>
                        <div className="flex items-center gap-3 text-xs text-white/30 font-medium font-serif">
                          <User size={14} className="text-saffron/40" />
                          {book.author || 'Anonymous Seeker'}
                        </div>
                      </div>
                    </td>
                    <td className="px-10 py-8 text-center">
                      <span className="inline-flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest bg-white/5 text-white/60 border border-white/10 shadow-lg">
                        <Languages size={12} className="text-saffron/60" />
                        {book.language}
                      </span>
                    </td>
                    <td className="px-10 py-8">
                      <span className="inline-flex items-center gap-2.5 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest bg-saffron/5 text-saffron border border-saffron/20 shadow-[0_0_20px_rgba(245,158,11,0.05)]">
                        <Tag size={12} />
                        {book.genre || 'General Wisdom'}
                      </span>
                    </td>
                    <td className="px-10 py-8">
                      <span className={`inline-flex items-center gap-3 text-[10px] font-black uppercase tracking-[0.2em] ${
                        book.status === 'published' ? 'text-emerald-400' : 'text-saffron'
                      }`}>
                        <span className={`w-2 h-2 rounded-full ${
                          book.status === 'published' ? 'bg-emerald-400 shadow-[0_0_12px_rgba(52,211,153,0.6)] animate-pulse' : 'bg-saffron shadow-[0_0_12px_rgba(245,158,11,0.6)]'
                        }`} />
                        {book.status}
                      </span>
                    </td>
                    <td className="px-10 py-8 text-right">
                      <div className="flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all duration-500 translate-x-4 group-hover:translate-x-0">
                        {permissions?.can_edit && (
                          <Button variant="ghost" size="icon" className="h-11 w-11 text-white/20 hover:text-white hover:bg-white/10 rounded-2xl transition-all shadow-xl border border-transparent hover:border-white/5">
                            <Pencil size={20} />
                          </Button>
                        )}
                        {permissions?.can_delete && <DeleteBookButton id={book.id} />}
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={5} className="px-10 py-40 text-center">
                    <div className="flex flex-col items-center max-w-sm mx-auto">
                      <div className="relative group/empty mb-10">
                        <div className="absolute inset-0 bg-saffron/20 blur-3xl rounded-full opacity-50 group-hover/empty:opacity-100 transition-opacity duration-1000" />
                        <div className="relative w-28 h-28 bg-white/[0.03] rounded-[2.5rem] flex items-center justify-center border border-white/10 backdrop-blur-3xl shadow-inner overflow-hidden">
                          <BookOpen size={44} className="text-white/10 group-hover/empty:text-saffron transition-all duration-700 group-hover/empty:scale-110" />
                          <div className="absolute inset-0 bg-gradient-to-tr from-saffron/10 to-transparent opacity-0 group-hover/empty:opacity-100 transition-opacity" />
                        </div>
                      </div>
                      <h3 className="font-bold text-white text-3xl mb-4 tracking-tight">
                        {q ? 'No matching manuscripts' : 'Archive is empty'}
                      </h3>
                      <p className="text-white/40 mb-12 text-base font-medium italic leading-relaxed font-serif">
                        {q 
                          ? `The sacred texts don't seem to contain any wisdom matching "${q}". Please try an alternative path.` 
                          : 'Your collection of sacred texts is waiting to be built. Begin by anchoring your first piece of wisdom.'}
                      </p>
                      {permissions?.can_write && !q && (
                        <div className="flex justify-center scale-110">
                          <AddBookForm />
                        </div>
                      )}
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
      
      {/* Footer Insight */}
      <div className="flex items-center justify-center py-6 text-[10px] font-black uppercase tracking-[0.4em] text-white/10">
        <Sparkles size={14} className="mr-4" />
        Curating Eternal Knowledge
      </div>
    </div>
  );
}
